+        TempProcessedItem: Record Item temporary;
+        RequisitionLine: Record "Requisition Line";
+    begin
+        // Find Planning Components that were created during this run but whose items
+        // were processed before the Planning Component existed (no requisition line was created).
+        // This can happen when items have the same Low-Level Code (e.g., both 0) and
+        // the component item is processed before the parent item that creates the Planning Component.
+        if TempPlanningCompList.Find('-') then
